codeExamples.code:
-- 연습용 DB 생성 (문자셋 명시)
CREATE DATABASE practice_db
  CHARACTER SET utf8mb4
  COLLATE utf8mb4_unicode_ci;

-- 생성 확인
SHOW DATABASES;

-- 해당 DB 선택 (이후 모든 명령은 이 DB 기준으로 실행됨)
USE practice_db;

-- 현재 선택된 DB 확인
SELECT DATABASE();
-- 출력: practice_db

-- MySQL에서 아래 두 명령은 완전히 동일하다
CREATE DATABASE shop_db;
CREATE SCHEMA shop_db;   -- 같은 결과

SHOW DATABASES;
SHOW SCHEMAS;            -- 같은 결과

-- JSON 타입 컬럼 정의
extra_info JSON

-- 저장
INSERT INTO products (extra_info) VALUES ('{"color": "red", "size": "M"}');

-- JSON 내부 값 조회
SELECT extra_info->>'$.color' FROM products;
-- 결과: red

-- JSON 내부 값으로 조건 검색
SELECT * FROM products WHERE extra_info->>'$.size' = 'M';

-- 문자열: 작은따옴표('') 사용 (표준)
WHERE name = '홍길동';

-- 큰따옴표("") 도 가능하지만 ANSI_QUOTES 설정에 따라 다르게 해석될 수 있음
WHERE name = "홍길동";   -- 권장하지 않음

-- 날짜: 문자열 형식으로 작성 (MySQL이 자동 변환)
WHERE created_at >= '2024-01-01';
WHERE birth_date = '1990-05-15';

-- 문법 오류 예시: FORM (오타)
SELECT * FORM members;
-- ERROR 1064 (42000): You have an error in your SQL syntax;
-- check the manual that corresponds to your MySQL server version
-- for the right syntax to use near 'FORM members' at line 1

-- DML 실행 전 안전 확인 패턴
-- 1단계: SELECT로 영향받을 행 먼저 확인
SELECT * FROM members WHERE status = 'deleted';

-- 2단계: 확인 후 DELETE 실행
DELETE FROM members WHERE status = 'deleted';

-- DDL: 컬럼 추가
ALTER TABLE reviews
ADD COLUMN helpful_count INT UNSIGNED NOT NULL DEFAULT 0;

-- DML: 새로운 데이터 행 추가
INSERT INTO reviews (product_id, user_id, rating, content)
VALUES (5, 42, 4, '배송도 빠르고 품질도 좋네요!');

-- 안전 확인: SELECT로 먼저 확인
SELECT * FROM reviews WHERE user_id = 99;
-- 3건 확인됨

-- DML: 데이터 삭제
DELETE FROM reviews WHERE user_id = 99;

-- TCL: 영구 반영
COMMIT;

-- DCL: 계정 생성 및 권한 부여
CREATE USER 'new_dba'@'localhost' IDENTIFIED BY 'password123';
GRANT SELECT ON shop_db.* TO 'new_dba'@'localhost';
FLUSH PRIVILEGES;

-- DDL: 빠른 전체 삭제 (복구 불필요한 개발 환경)
TRUNCATE TABLE reviews;
-- AUTO_INCREMENT도 1로 초기화됨

-- ALTER: 컬럼 추가
ALTER TABLE sql_study
ADD COLUMN grade CHAR(1) NULL;

-- 구조 변경 확인
DESC sql_study;

-- 추가된 컬럼에 데이터 업데이트
UPDATE sql_study SET grade = 'A' WHERE score >= 90;
UPDATE sql_study SET grade = 'B' WHERE score >= 80 AND score < 90;

SELECT * FROM sql_study;

-- 현재 상태 확인
SELECT * FROM sql_study;

-- 트랜잭션 시작
START TRANSACTION;

-- 실수로 전체 데이터 삭제
DELETE FROM sql_study;

-- 삭제 확인 (아직 커밋 전이므로 현재 세션에서만 삭제된 것처럼 보임)
SELECT * FROM sql_study;
-- 결과: Empty set

-- 실수 인지 → ROLLBACK으로 복구
ROLLBACK;

-- 복구 확인
SELECT * FROM sql_study;
-- 데이터 다시 나타남!

CREATE TABLE 테이블명 (
    컬럼명   데이터타입   [컬럼 제약조건],
    컬럼명   데이터타입   [컬럼 제약조건],
    ...
    [테이블 제약조건]
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- 컬럼 추가
ALTER TABLE members ADD COLUMN nickname VARCHAR(50) NULL;

-- 컬럼 삭제
ALTER TABLE members DROP COLUMN nickname;

-- 컬럼 타입 변경
ALTER TABLE members MODIFY COLUMN name VARCHAR(100) NOT NULL;

-- 컬럼 이름 + 타입 동시 변경
ALTER TABLE members CHANGE COLUMN name full_name VARCHAR(100) NOT NULL;

-- 제약조건 추가
ALTER TABLE members ADD CONSTRAINT uq_phone UNIQUE (phone);

-- 제약조건 삭제
ALTER TABLE members DROP INDEX uq_phone;

-- 테이블 이름 변경
RENAME TABLE members TO users;

CREATE TABLE members (
    email      VARCHAR(100) NOT NULL,  ← PK
    name       VARCHAR(50)  NOT NULL,
    created_at DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (email)
);

USE practice_db;

-- 기존 테이블이 있으면 삭제 후 재생성
DROP TABLE IF EXISTS products;
DROP TABLE IF EXISTS categories;
DROP TABLE IF EXISTS users;

-- 요구사항 변경: products에 discount_rate 컬럼 추가
ALTER TABLE products
ADD COLUMN discount_rate DECIMAL(5,2) NOT NULL DEFAULT 0.00
AFTER price;

-- 추가 확인
DESC products;

-- CHECK 제약조건 추가 (할인율은 0~100% 사이)
ALTER TABLE products
ADD CONSTRAINT chk_discount_rate CHECK (discount_rate BETWEEN 0 AND 100);

-- CHECK 위반 테스트
INSERT INTO products (category_id, name, price, discount_rate)
VALUES (1, '테스트 상품', 50000, 150);
-- ERROR 3819 (HY000): Check constraint 'chk_discount_rate' is violated.

-- 올바른 값으로 INSERT
INSERT INTO products (category_id, name, price, discount_rate)
VALUES (1, 'Galaxy S24', 1200000, 10.00);

SELECT * FROM products;

-- 실제 예시
INSERT INTO users (name, email, password)
VALUES ('홍길동', 'hong@example.com', '$2b$10$abc...');

-- PK 또는 UNIQUE 충돌 시 기존 행 DELETE 후 새로 INSERT
REPLACE INTO users (id, name, email)
VALUES (1, '홍길동(수정)', 'hong_new@example.com');

-- 방법 1: 컬럼 목록에서 AUTO_INCREMENT 컬럼을 제외 (권장)
INSERT INTO users (name, email) VALUES ('홍길동', 'hong@ex.com');
-- id는 자동 할당됨

-- 방법 2: NULL을 명시적으로 입력
INSERT INTO users (id, name, email) VALUES (NULL, '홍길동', 'hong@ex.com');
-- NULL → 자동 증가값으로 처리됨

-- 방법 3: 0을 입력 (NULL과 동일하게 처리)
INSERT INTO users (id, name, email) VALUES (0, '홍길동', 'hong@ex.com');

-- 방법 4: 직접 값을 지정 (특수한 경우에만)
INSERT INTO users (id, name, email) VALUES (100, '홍길동', 'hong@ex.com');
-- 다음 AUTO_INCREMENT는 101부터 시작함

-- 마지막으로 생성된 AUTO_INCREMENT 값 확인
SELECT LAST_INSERT_ID();
-- 현재 세션에서 가장 최근 INSERT로 생성된 id 반환

-- 패턴 1: 트랜잭션으로 묶어 전체 성공 또는 전체 실패
START TRANSACTION;

INSERT INTO orders (user_id, total_price) VALUES (42, 35000);
-- id=201 생성됨

INSERT INTO order_items (order_id, product_id, qty, price)
VALUES (201, 7, 2, 35000);

-- 여기서 실패하면 orders와 order_items 모두 롤백
COMMIT;

-- 패턴 2: SAVEPOINT로 부분 복구
START TRANSACTION;

INSERT INTO orders (user_id) VALUES (42);
SAVEPOINT sp_order_created;

INSERT INTO order_items (order_id, product_id) VALUES (LAST_INSERT_ID(), 7);
-- 실패 시
ROLLBACK TO SAVEPOINT sp_order_created;  -- order_items만 취소
-- orders는 유지된 채로 다음 처리 가능

COMMIT;

USE practice_db;

-- Step 05에서 만든 테이블 확인
SHOW TABLES;
-- users, categories, products 가 있어야 함

-- 없다면 Step 05 실습을 먼저 진행

-- 에러 1: NOT NULL 위반
INSERT INTO users (email, password) VALUES ('test@ex.com', 'hash');
-- ERROR 1364 (HY000): Field 'name' doesn't have a default value
-- 해결: NOT NULL 컬럼(name)에 반드시 값을 제공해야 함
INSERT INTO users (name, email, password) VALUES ('테스트', 'test@ex.com', 'hash');

-- 에러 2: UNIQUE 중복
INSERT INTO users (name, email, password) VALUES ('홍길동2', 'hong@example.com', 'hash');
-- ERROR 1062 (23000): Duplicate entry 'hong@example.com' for key 'uq_users_email'
-- 해결: 다른 이메일을 사용하거나, ON DUPLICATE KEY UPDATE 활용

-- 에러 3: 데이터 길이 초과
INSERT INTO users (name, email, password)
VALUES ('이름이매우매우매우매우매우매우매우길어서오십자를초과하는케이스입니다', 'long@ex.com', 'hash');
-- ERROR 1406 (22001): Data too long for column 'name' at row 1
-- 해결: 입력값 길이를 제한하거나 컬럼 크기를 늘림

-- 에러 4: ENUM 범위 초과
INSERT INTO users (name, email, password, status)
VALUES ('테스트2', 'test2@ex.com', 'hash', 'banned');
-- ERROR 1265 (01000): Data truncated for column 'status' at row 1
-- 해결: ENUM에 정의된 값('active','inactive','deleted') 중 하나를 사용

-- 에러 5: 잘못된 날짜 형식
INSERT INTO users (name, email, password, birth_date)
VALUES ('테스트3', 'test3@ex.com', 'hash', '90/03/15');
-- ERROR 1292 (22007): Incorrect date value: '90/03/15' for column 'birth_date'
-- 해결: YYYY-MM-DD 형식 사용
INSERT INTO users (name, email, password, birth_date)
VALUES ('테스트3', 'test3@ex.com', 'hash', '1990-03-15');

-- 최종 상태 확인
SELECT COUNT(*) AS 총_회원수 FROM users;
SELECT COUNT(*) AS 총_상품수 FROM products;

-- A
INSERT INTO users (name, email) VALUES ('홍길동', 'hong@ex.com');

-- B
INSERT INTO users (name, email) VALUES
    ('홍길동', 'hong@ex.com'),
    ('김영희', 'kim@ex.com'),
    ('이철수', 'lee@ex.com');

-- C
INSERT INTO users_archive (id, name, email)
SELECT id, name, email FROM users WHERE status = 'deleted';

-- D
INSERT INTO stats (product_id, view_count) VALUES (1, 1)
ON DUPLICATE KEY UPDATE view_count = view_count + 1;

-- 문제 1
INSERT INTO users (name, status) VALUES ('홍길동', 'active');

-- 문제 2
INSERT INTO users (name, email, status) VALUES ('김영희', 'hong@example.com', 'banned');

-- 문제 3
INSERT INTO users VALUES ('이철수', 'lee@example.com', 'hash', 'active');

-- email은 NOT NULL이므로 반드시 값 필요
INSERT INTO users (name, email, password, status)
VALUES ('홍길동', 'hong2@example.com', '$2b$10$hash', 'active');

INSERT INTO users (name, email, password, status)
VALUES ('김영희', 'kim2@example.com', '$2b$10$hash', 'inactive');
-- 또는 'active', 'deleted' 중 선택

-- 컬럼명을 명시하는 방법 1 사용 (권장)
INSERT INTO users (name, email, password, status)
VALUES ('이철수', 'lee@example.com', '$2b$10$hash', 'active');

SELECT * FROM users;
-- 테이블의 모든 컬럼을 순서대로 출력
-- 개발/디버깅 시 편리하지만 운영 코드에서는 지양

-- 필요한 컬럼만 명시
SELECT id, name, email FROM users;

-- 컬럼 순서는 테이블 정의와 달라도 됨
SELECT email, id, name FROM users;

-- AS 키워드로 컬럼에 별칭 부여
SELECT
    name        AS 이름,
    email       AS 이메일,
    point       AS 포인트
FROM users;

-- AS 생략 가능 (권장하지 않음 — 가독성 저하)
SELECT name 이름, email 이메일 FROM users;

-- 별칭에 공백이 포함되면 따옴표 필요
SELECT name AS '회원 이름' FROM users;

-- 중복된 값을 제거하고 유일한 값만 출력
SELECT DISTINCT status FROM users;
-- 출력: active / inactive / deleted (중복 없이)

-- 여러 컬럼 조합의 중복 제거
SELECT DISTINCT status, point FROM users;
-- status + point 조합이 동일한 경우만 중복으로 처리

-- 활성 사용자만 조회
SELECT name, email FROM users WHERE status = 'active';

-- 가격이 100만원 이상인 상품
SELECT name, price FROM products WHERE price >= 1000000;

-- 삭제된 사용자가 아닌 경우
SELECT name FROM users WHERE status <> 'deleted';

-- ASC: 오름차순 (기본값, 생략 가능)
SELECT name, point FROM users ORDER BY point ASC;
SELECT name, point FROM users ORDER BY point;      -- 동일

-- DESC: 내림차순
SELECT name, point FROM users ORDER BY point DESC;

-- Q1. 몇 건이 반환될까?
SELECT name FROM users
WHERE status = 'active'
  AND (point >= 3000 OR point = 0);

-- Q2. 어떤 순서로 반환될까?
SELECT name, point
FROM users
WHERE status != 'deleted'
ORDER BY status ASC, point DESC;

-- Q3. 이 쿼리의 결과는 몇 건? 왜?
SELECT name FROM users
WHERE phone = NULL;

-- Q4. 이 두 쿼리의 결과 건수가 같을까?
SELECT DISTINCT status FROM users;
SELECT status FROM users GROUP BY status;

SELECT name, point * 2 AS bonus
FROM users
WHERE point * 2 > 2000;

SELECT name, bonus
FROM (
    SELECT name, point * 2 AS bonus
    FROM users
) AS sub
WHERE bonus > 2000;

-- id=9인 회원 삭제
DELETE FROM users
WHERE id = 9;

-- 테이블의 모든 데이터를 빠르게 전체 삭제
TRUNCATE TABLE 테이블명;
-- 또는
TRUNCATE 테이블명;

WHERE 절 없음 = 테이블의 모든 행이 대상

UPDATE users SET point = 0;
→ 10명 회원 전체의 포인트가 0으로 변경

DELETE FROM users;
→ 테이블의 모든 행 삭제 (구조는 남음)

-- Safe Update Mode 비활성화 (임시로 해제 필요할 때)
SET SQL_SAFE_UPDATES = 0;

-- 작업 후 다시 활성화
SET SQL_SAFE_UPDATES = 1;

-- 회원 탈퇴 처리 (논리 삭제)
UPDATE users
SET    status     = 'deleted',
       updated_at = NOW()
WHERE  id = 9;

-- 데이터는 테이블에 남아있음
SELECT id, name, status FROM users WHERE id = 9;
-- 결과: id=9, 임재원, deleted

-- 조회 시 삭제된 회원 제외 필터 필요
SELECT * FROM users WHERE status != 'deleted';

USE practice_db;

-- 현재 데이터 상태 확인
SELECT id, name, point, status FROM users ORDER BY id;
SELECT id, name, price, stock, status FROM products ORDER BY id;

-- Safe Update Mode 활성화
SET SQL_SAFE_UPDATES = 1;

-- WHERE 없는 UPDATE 시도 → 에러 발생
UPDATE users SET grade = 'TEST';
-- ERROR 1175 (HY000): You are using safe update mode...

-- PK 기반 WHERE는 허용
UPDATE users SET grade = 'VIP' WHERE id = 1;  -- ✅ 성공

-- Safe Update Mode 비활성화 (필요 시)
SET SQL_SAFE_UPDATES = 0;

-- 목표: id=9(임재원) 회원을 논리 삭제 방식으로 처리

-- 현재 상태 확인
SELECT id, name, status, updated_at FROM users WHERE id = 9;

-- 논리 삭제 (UPDATE로 상태 변경)
UPDATE users
SET    status     = 'deleted',
       updated_at = NOW()
WHERE  id = 9;

-- 삭제 후 상태 확인 (데이터는 남아있음)
SELECT id, name, status, updated_at FROM users WHERE id = 9;

-- 논리 삭제된 회원 제외 조회
SELECT id, name, status FROM users WHERE status != 'deleted';

-- 논리 삭제 취소 (복구)
UPDATE users
SET    status     = 'active',
       updated_at = NOW()
WHERE  id = 9;

SELECT id, name, status FROM users WHERE id = 9;
-- 복구 확인

-- 트랜잭션으로 안전하게 위험 상황을 체험한다.

-- 현재 포인트 상태 기록
SELECT id, name, point FROM users;

-- 트랜잭션 시작
START TRANSACTION;

-- WHERE 없는 UPDATE 실행
UPDATE users SET point = 0;

-- 결과 확인: 전체 회원 포인트가 0으로 변경됨
SELECT id, name, point FROM users;
-- 모든 회원의 point가 0

-- ROLLBACK으로 복구!
ROLLBACK;

-- 복구 확인: 원래 포인트로 돌아왔는지 확인
SELECT id, name, point FROM users;

-- 문제 1: 특정 상품의 가격을 수정하려 했으나 의도와 다르게 동작할 수 있다.
UPDATE products SET price = 999000 WHERE name = 'Galaxy S24';

-- 문제 2: 포인트가 0인 비활성 회원을 삭제하려 한다.
DELETE users WHERE status = 'inactive' AND point = 0;

-- 문제 3: 2024년에 가입한 회원의 grade를 'NEW'로 변경하려 한다.
UPDATE users SET grade = 'NEW'
WHERE created_at = '2024';

-- 트랜잭션 시작 (두 방법은 동일)
START TRANSACTION;
BEGIN;
-- 또는
BEGIN WORK;

-- 이 시점부터 실행되는 DML은 트랜잭션에 포함됨

-- 트랜잭션 내 모든 변경을 취소하고 이전 상태로 복원
ROLLBACK;
-- 트랜잭션 시작(START TRANSACTION) 시점의 상태로 되돌아감

-- 트랜잭션 내 특정 시점에 저장점(체크포인트) 설정
SAVEPOINT 저장점이름;

-- 특정 저장점까지만 롤백 (저장점 이후 변경만 취소)
ROLLBACK TO SAVEPOINT 저장점이름;
-- 또는 축약형
ROLLBACK TO 저장점이름;

-- 저장점 삭제
RELEASE SAVEPOINT 저장점이름;

-- 현재 Auto Commit 상태 확인
SHOW VARIABLES LIKE 'autocommit';
-- Value: ON (기본값)

-- Auto Commit 비활성화 (현재 세션)
SET autocommit = 0;   -- 또는 SET autocommit = OFF;

-- 다시 활성화
SET autocommit = 1;   -- 또는 SET autocommit = ON;

암묵적 커밋을 유발하는 상황:

1. DDL 실행
   START TRANSACTION;
   DELETE FROM users WHERE id = 9;
   CREATE TABLE temp_log (...);  ← DDL 실행 → 암묵적 커밋 발생!
   ROLLBACK;  ← DELETE도 함께 커밋되어 복구 불가!

2. DCL 실행
   START TRANSACTION;
   UPDATE users SET point = 0;
   GRANT SELECT ON shop_db.* TO 'user'@'localhost';  ← 암묵적 커밋!
   ROLLBACK;  ← UPDATE 복구 불가!

3. 다른 트랜잭션 시작
   START TRANSACTION;
   UPDATE users SET point = 0;
   START TRANSACTION;  ← 이전 트랜잭션 암묵적 커밋!

[세션 A]                        [세션 B]
─────────────────────────────────────────────────────
START TRANSACTION;

UPDATE users
SET point = 0
WHERE id = 1;
-- id=1 point = 0 (아직 커밋 안 됨)
                                SELECT point FROM users
                                WHERE id = 1;
                                -- 결과: 1500 (커밋 전 값 읽음)
                                -- Undo Log의 이전 버전을 읽음

COMMIT;
                                SELECT point FROM users
                                WHERE id = 1;
                                -- 결과: 0 (커밋 후 새 값 읽음)

START TRANSACTION;

-- 작업 1: 주문 생성
INSERT INTO orders (user_id, total) VALUES (1, 50000);
SAVEPOINT sp_order_created;  ← 저장점 A

-- 작업 2: 주문 상품 추가
INSERT INTO order_items (order_id, product_id, qty) VALUES (LAST_INSERT_ID(), 3, 2);
SAVEPOINT sp_items_added;    ← 저장점 B

-- 작업 3: 재고 차감
UPDATE products SET stock = stock - 2 WHERE id = 3;
-- 이 시점에서 재고 부족 감지! (-1이 됨)

-- 저장점 B까지만 롤백 (재고 차감만 취소, 주문과 상품은 유지)
ROLLBACK TO SAVEPOINT sp_items_added;

-- 재고 있는 다른 방법으로 처리...
UPDATE products SET stock = 0 WHERE id = 3;

COMMIT;
-- 주문 + 상품 + 재고 차감(수정 후) 모두 커밋됨

-- 계좌 테이블 (시나리오용)
CREATE TABLE accounts (
    id      VARCHAR(10)    NOT NULL,
    name    VARCHAR(50)    NOT NULL,
