    PRIMARY KEY (id)
);

INSERT INTO accounts VALUES
    ('A001', '홍길동', 1000000),
    ('B001', '김영희',  500000);

SELECT * FROM accounts;
-- A001: 1,000,000원
-- B001:   500,000원

START TRANSACTION;

-- 현재 잔액 확인 (900,000원)
SELECT balance FROM accounts WHERE id = 'A001';

-- 2,000,000원 이체 시도
UPDATE accounts
SET    balance = balance - 2000000
WHERE  id = 'A001';
-- balance가 UNSIGNED이므로 언더플로우 에러 또는 0으로 처리됨

-- 애플리케이션이 오류 감지 → 전체 취소
ROLLBACK;

-- 잔액 확인: 변화 없어야 함
SELECT id, name, balance FROM accounts;
-- A001: 900,000 (ROLLBACK으로 복원됨)
