START TRANSACTION;

-- 1단계: 포인트 적립 이벤트 (홍길동에게 5,000 포인트)
UPDATE users SET point = point + 5000 WHERE id = 1;
SELECT point FROM users WHERE id = 1;  -- 확인: 6500
SAVEPOINT sp_point_done;

-- 2단계: 등급 업데이트
UPDATE users SET grade = 'GOLD' WHERE id = 1;
SAVEPOINT sp_grade_done;

-- 3단계: 이벤트 쿠폰 발급 (가상)
-- ... 이 단계에서 오류 발생 (쿠폰 테이블이 없다고 가정)
-- INSERT INTO coupons ...  → 에러!

-- 3단계만 취소 (쿠폰 발급 취소), 1·2단계는 유지
ROLLBACK TO SAVEPOINT sp_grade_done;

-- 1·2단계 결과 확인
SELECT id, name, point, grade FROM users WHERE id = 1;
-- point: 6500 (1단계 반영됨)
-- grade: GOLD  (2단계 반영됨)

-- 3단계는 추후 재처리 예정
COMMIT;

[환경 1] Auto Commit ON + 트랜잭션 없음 (가장 위험)

UPDATE accounts SET balance = balance - 100000 WHERE id = 'A001';
-- 즉시 커밋: 복구 불가
-- 서버 장애 발생 시 다음 UPDATE는 실행 안 됨
UPDATE accounts SET balance = balance + 100000 WHERE id = 'B001';
-- 절대 보장 없음 → 데이터 불일치

[환경 2] Auto Commit ON + 명시적 트랜잭션 (권장)

START TRANSACTION;
UPDATE accounts SET balance = balance - 100000 WHERE id = 'A001';
UPDATE accounts SET balance = balance + 100000 WHERE id = 'B001';
COMMIT;
-- 두 UPDATE가 하나의 단위로 처리됨
-- 하나가 실패하면 전체 ROLLBACK

[환경 3] Auto Commit OFF + 명시적 COMMIT 누락 (위험)

SET autocommit = 0;
UPDATE accounts SET balance = balance - 100000 WHERE id = 'A001';
-- COMMIT 없이 연결이 끊김 → 자동 ROLLBACK
-- 이체가 아예 처리되지 않음 (덜 위험하지만 혼란 유발)

