dbdiagram.io에서 사용하는 DBML 문법:

Table users {
  id         int        [pk, increment]
  name       varchar(50) [not null]
  email      varchar(100) [not null, unique]
  status     varchar(10)  [default: 'active']
  created_at datetime    [default: `now()`]
}

Table orders {
  id         int        [pk, increment]
  user_id    int        [not null, ref: > users.id]  // 1:N
  total      decimal
  status     varchar(20)
  created_at datetime
}

Table order_items {
  order_id   int        [ref: > orders.id]    // 복합 PK
  product_id int        [ref: > products.id]  // 복합 PK
  qty        int
  price      decimal

  indexes {
    (order_id, product_id) [pk]
  }
}

