-- id=1 행에 X-Lock 획득

-- [세션 B] 동시에 같은 행 수정 시도
START TRANSACTION;
UPDATE users SET point = 0 WHERE id = 1;
-- 대기 상태! (세션 A가 X-Lock 보유 중)
-- innodb_lock_wait_timeout 초 후 타임아웃 또는 세션 A 커밋 시 진행

-- [세션 A] 커밋
UPDATE users SET point = point + 100 WHERE id = 1;
COMMIT;
-- 커밋 후 세션 B가 잠금 획득하고 진행

-- [세션 B] 이제 실행됨 (잠금 해제 후)
COMMIT;

-- 최종 point 확인
SELECT id, name, point FROM users WHERE id = 1;

-- 실습 테이블 준비
CREATE TABLE deadlock_test (
    id    INT PRIMARY KEY,
    value INT
);
INSERT INTO deadlock_test VALUES (1, 100), (2, 200);

-- [세션 A]
START TRANSACTION;
UPDATE deadlock_test SET value = value + 10 WHERE id = 1;
-- id=1 X-Lock 획득

-- [세션 B]
START TRANSACTION;
UPDATE deadlock_test SET value = value + 10 WHERE id = 2;
-- id=2 X-Lock 획득

-- [세션 B] id=1 잠금 시도 → 데드락!
UPDATE deadlock_test SET value = value + 10 WHERE id = 1;
-- ERROR 1213 (40001): Deadlock found when trying to get lock;
-- try restarting transaction
-- → 세션 B가 자동으로 희생자(Victim)로 선택되어 ROLLBACK됨
-- → 세션 A는 정상 진행됨

-- 트랜잭션 X
START TRANSACTION;
UPDATE accounts SET balance = balance - 10000 WHERE id = 'ACC-001';
UPDATE accounts SET balance = balance + 10000 WHERE id = 'ACC-002';
COMMIT;

-- 트랜잭션 Y (동시에 실행)
START TRANSACTION;
UPDATE accounts SET balance = balance - 5000 WHERE id = 'ACC-002';
UPDATE accounts SET balance = balance + 5000 WHERE id = 'ACC-001';
COMMIT;

-- 두 트랜잭션 모두 ACC-001 → ACC-002 순서로 처리
-- X: ACC-001 → ACC-002 (원래 순서 유지)
-- Y: ACC-001 → ACC-002 (순서 변경 필요)
START TRANSACTION;
UPDATE accounts SET balance = balance + 5000 WHERE id = 'ACC-001';  -- 먼저!
UPDATE accounts SET balance = balance - 5000 WHERE id = 'ACC-002';
COMMIT;

