    IN  파라미터1  데이터타입,   -- 입력 파라미터
    OUT 파라미터2  데이터타입,   -- 출력 파라미터
    INOUT 파라미터3 데이터타입   -- 입출력 파라미터
)
BEGIN
    -- 변수 선언
    DECLARE 변수명 데이터타입 DEFAULT 기본값;

    -- SQL 문장들
    SELECT ...;
    INSERT ...;
    UPDATE ...;

    -- 제어 흐름
    IF 조건 THEN
        ...
    ELSEIF 조건 THEN
        ...
    ELSE
        ...
    END IF;

    WHILE 조건 DO
        ...
    END WHILE;

END$$

