-- WHILE 반복
CREATE PROCEDURE count_up_to(IN p_limit INT)
BEGIN
    DECLARE v_i INT DEFAULT 1;
    DECLARE v_result VARCHAR(200) DEFAULT '';

    WHILE v_i <= p_limit DO
        SET v_result = CONCAT(v_result, v_i, ' ');
        SET v_i = v_i + 1;
    END WHILE;

    SELECT v_result AS 결과;
END$$

-- LOOP + LEAVE (명시적 종료)
CREATE PROCEDURE loop_demo()
BEGIN
    DECLARE v_i INT DEFAULT 1;

    my_loop: LOOP
        IF v_i > 5 THEN
            LEAVE my_loop;  -- 루프 탈출
        END IF;
        SET v_i = v_i + 1;
    END LOOP;

    SELECT v_i AS 최종값;
END$$

-- REPEAT ~ UNTIL (do-while 방식)
CREATE PROCEDURE repeat_demo()
BEGIN
    DECLARE v_i INT DEFAULT 1;

    REPEAT
        SET v_i = v_i + 1;
    UNTIL v_i > 5     -- 조건이 참이면 종료
    END REPEAT;

    SELECT v_i AS 최종값;
END$$

DELIMITER ;

CALL count_up_to(5);
CALL loop_demo();
CALL repeat_demo();

