CREATE PROCEDURE process_all_users()
BEGIN
    DECLARE v_done     INT DEFAULT 0;
    DECLARE v_user_id  INT;
    DECLARE v_point    INT;

    -- 커서 선언
    DECLARE user_cursor CURSOR FOR
        SELECT id, point FROM users WHERE status = 'active';

    -- NOT FOUND 핸들러 (더 이상 행이 없을 때)
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_done = 1;

    -- 커서 열기
    OPEN user_cursor;

    fetch_loop: LOOP
        -- 한 행씩 가져오기
        FETCH user_cursor INTO v_user_id, v_point;

        IF v_done = 1 THEN
            LEAVE fetch_loop;
        END IF;

        -- 각 행 처리
        IF v_point >= 3000 THEN
            UPDATE users SET grade = 'GOLD'   WHERE id = v_user_id;
        ELSEIF v_point >= 1000 THEN
            UPDATE users SET grade = 'SILVER' WHERE id = v_user_id;
        ELSE
            UPDATE users SET grade = 'BRONZE' WHERE id = v_user_id;
        END IF;

    END LOOP;

    -- 커서 닫기
    CLOSE user_cursor;

    SELECT '전체 회원 등급 업데이트 완료' AS 결과;
END$$

