USE practice_db;

-- 월별 통계 테이블
CREATE TABLE IF NOT EXISTS monthly_sales (
    ym          CHAR(7)       NOT NULL,  -- '2024-01'
    total_orders INT UNSIGNED  NOT NULL DEFAULT 0,
    total_amount BIGINT UNSIGNED NOT NULL DEFAULT 0,
    created_at  DATETIME      NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (ym)
);

-- 배치 로그 테이블
CREATE TABLE IF NOT EXISTS batch_logs (
    id          INT UNSIGNED  NOT NULL AUTO_INCREMENT,
    proc_name   VARCHAR(100)  NOT NULL,
    status      ENUM('success','failed') NOT NULL,
    message     TEXT          NULL,
    executed_at DATETIME      NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id)
);

DELIMITER $$

CREATE PROCEDURE monthly_settlement(IN p_ym CHAR(7))
-- p_ym: 정산 대상 연월 (예: '2024-01')
BEGIN
    DECLARE v_total_orders  INT     DEFAULT 0;
    DECLARE v_total_amount  BIGINT  DEFAULT 0;
    DECLARE v_error_msg     TEXT    DEFAULT NULL;
    DECLARE v_start_date    DATE;
    DECLARE v_end_date      DATE;

    -- 에러 핸들러
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1 v_error_msg = MESSAGE_TEXT;
        ROLLBACK;
        INSERT INTO batch_logs (proc_name, status, message)
        VALUES ('monthly_settlement', 'failed',
                CONCAT('[', p_ym, '] 오류: ', v_error_msg));
    END;

    -- 날짜 범위 계산
    SET v_start_date = STR_TO_DATE(CONCAT(p_ym, '-01'), '%Y-%m-%d');
    SET v_end_date   = LAST_DAY(v_start_date);

    START TRANSACTION;

    -- 1단계: 월별 매출 집계
    SELECT COUNT(*), COALESCE(SUM(total_price), 0)
    INTO   v_total_orders, v_total_amount
    FROM   orders
    WHERE  status = 'completed'
      AND  created_at >= v_start_date
      AND  created_at <= v_end_date;

    -- 2단계: 월별 통계 저장 (중복 실행 시 UPDATE)
    INSERT INTO monthly_sales (ym, total_orders, total_amount)
    VALUES (p_ym, v_total_orders, v_total_amount)
    ON DUPLICATE KEY UPDATE
        total_orders = v_total_orders,
        total_amount = v_total_amount;

    -- 3단계: 회원별 포인트 적립 (구매액의 1%)
    UPDATE users u
    JOIN (
        SELECT user_id, FLOOR(SUM(total_price) * 0.01) AS earn_point
        FROM   orders
        WHERE  status = 'completed'
          AND  created_at >= v_start_date
          AND  created_at <= v_end_date
        GROUP BY user_id
    ) AS monthly ON u.id = monthly.user_id
    SET u.point = u.point + monthly.earn_point;

    -- 4단계: 성공 로그 기록
    INSERT INTO batch_logs (proc_name, status, message)
    VALUES ('monthly_settlement', 'success',
            CONCAT('[', p_ym, '] 주문 ', v_total_orders, '건, 매출 ',
                   FORMAT(v_total_amount, 0), '원 정산 완료'));

    COMMIT;

    -- 결과 출력
    SELECT
        p_ym             AS 정산월,
        v_total_orders   AS 주문건수,
        v_total_amount   AS 총매출,
        '성공'           AS 상태;
END$$

DELIMITER ;

