CREATE PROCEDURE safe_update_point(
    IN p_user_id INT,
    IN p_amount  INT,
    OUT p_success TINYINT
)
BEGIN
    DECLARE v_current INT;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        SET p_success = 0;
    END;

    START TRANSACTION;

    -- 현재 포인트 확인 (FOR UPDATE로 잠금)
    SELECT point INTO v_current
    FROM   users
    WHERE  id = p_user_id
    FOR UPDATE;

    -- 포인트가 0 미만이 되지 않도록
    IF v_current + p_amount < 0 THEN
        ROLLBACK;
        SET p_success = 0;
    ELSE
        UPDATE users SET point = point + p_amount WHERE id = p_user_id;
        COMMIT;
        SET p_success = 1;
    END IF;
END$$

