// 아래 HikariCP 설정을 보고 문제점을 찾아보세요

@Configuration
public class DataSourceConfig {

    // 설정 A (문제 있음)
    @Bean
    public DataSource problematicDataSource() {
        HikariConfig config = new HikariConfig();
        config.setJdbcUrl("jdbc:mysql://db:3306/shop");
        config.setMaximumPoolSize(200);          // ← 너무 큼?
        config.setConnectionTimeout(5000);
        config.setMaxLifetime(3600000);          // ← 1시간. 문제는?
        config.setIdleTimeout(60000);
        return new HikariDataSource(config);
    }

    // 설정 B (개선됨)
    @Bean
    public DataSource improvedDataSource() {
        HikariConfig config = new HikariConfig();
        config.setJdbcUrl("jdbc:mysql://db:3306/shop");
        config.setMaximumPoolSize(10);
        config.setMinimumIdle(5);
        config.setConnectionTimeout(30000);
        config.setMaxLifetime(1800000);          // 30분
        config.setIdleTimeout(600000);           // 10분
        config.setKeepaliveTime(30000);          // 30초 keepalive
        return new HikariDataSource(config);
    }
}
